frappe.ui.form.on('Asset', {
    refresh: function(frm) {
        // Give the default buttons time to render
        setTimeout(() => {
            // Remove "Sell Asset" button
            frm.page.remove_inner_button('Sell Asset', 'Manage');

            // Remove "Repair Asset" button
            frm.page.remove_inner_button('Repair Asset', 'Manage');
            frm.page.remove_inner_button('Split Asset', 'Manage');
            frm.page.remove_inner_button('Adjust Asset Value', 'Manage');
            //frm.page.remove_inner_button('Create Depreciation Entry', 'Manage');
            
            const user_roles = frappe.user_roles || [];

            // Remove Scrap Asset using both method and DOM fallback
            if (user_roles.includes('Asset Management User') && !user_roles.includes('Asset Management Head')) {
                // Try the default method
                frm.page.remove_inner_button('Scrap Asset', 'Manage');

                // Fallback using jQuery/DOM (in case ERPNext renders it late or dynamically)
                $("button:contains('Scrap Asset')").each(function () {
                    if ($(this).text().trim() === 'Scrap Asset') {
                        $(this).hide(); // or .remove();
                    }
                });
            }

            
        }, 300); // Delay just enough to override default buttons
    }
});

frappe.ui.form.on('Vehicle Log', {
  onload: function(frm) {
    frappe.call({
      method: "frappe.client.get",
      args: {
        doctype: "User",
        name: frappe.session.user,
      },
      callback: function(r) {
        if (r.message && r.message.location) {
          const user_location = r.message.location;

          frm.set_query("license_plate", function() {
            let allowed_locations = [];

           if (user_location === "GUYONG") {
              allowed_locations = ["GUYONG", "EDSA", "MC1"];
            } else {
              allowed_locations = [user_location];
            }

            return {
              filters: [
                ["Vehicle", "location", "in", allowed_locations]
              ]
            };
          });
        }
      }
    });
  }
});

frappe.ui.form.on('Sales Order Item', {
    item_code: function (frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (!frm.doc.customer || !row.item_code|| !frm.doc.company) return;

        // Fetch the latest rate and set it
        frappe.call({
            method: "get_previous_item_rates",
            args: {
                customer: frm.doc.customer,
                item_code: row.item_code,
                company: frm.doc.company
            },
            callback: function (r) {
                if (r.data && r.data.length > 0) {
                    frappe.model.set_value(cdt, cdn, 'rate', r.data[0].rate);
                }
            }
        });
    },

    custom_select_previous_rate: function (frm, cdt, cdn) {
        let row = locals[cdt][cdn];

        if (!frm.doc.customer || !row.item_code || !frm.doc.company) {
            frappe.msgprint("Please select a customer, company and item first.");
            return;
        }
 
       frappe.call({
            method: "get_previous_item_rates",
            args: {
                customer: frm.doc.customer,
                item_code: row.item_code,
                company: frm.doc.company
            },
            callback: function (r) {
                if (r.data && r.data.length > 0) {
                    let rates = r.data;

                    let html = `
                        <table class="table table-bordered" style="margin-top:10px;">
                            <thead>
                                <tr>
                                    <th>Select</th>
                                    <th>Rate</th>
                                    <th>Last Used Date</th>
                                    <th>Sales Orders</th>
                                </tr>
                            </thead>
                            <tbody>
                    `;

                    rates.forEach((entry, index) => {
                        html += `
                            <tr>
                                <td><input type="radio" name="rate_option" value="${entry.rate}" ${index === 0 ? "checked" : ""}></td>
                                <td>₱${entry.rate}</td>
                                <td>${frappe.datetime.str_to_user(entry.date)}</td>
                                <td>${entry.sales_orders || ""}</td>
                            </tr>
                        `;
                    });

                    html += `</tbody></table>`;

                    let d = new frappe.ui.Dialog({
                        title: 'Select Rate from Past Orders',
                        fields: [
                            {
                                fieldtype: 'HTML',
                                fieldname: 'rates_table',
                                options: html
                            }
                        ],
                        primary_action_label: 'Set Rate',
                        primary_action() {
                            let selected = d.$wrapper.find('input[name="rate_option"]:checked').val();
                            if (selected) {
                                frappe.model.set_value(cdt, cdn, 'rate', selected);
                            }
                            d.hide();
                        }
                    });

                    d.show();
                } else {
                    frappe.msgprint("No previous rates found for this item and customer.");
                }
            }
        });
        
        
    }
});

