frappe.listview_settings['Asset'] = {
    onload(listview) {
        listview.page.add_inner_button('Print Asset Tags', () => {
            const selected = listview.get_checked_items();

            if (selected.length === 0) {
                frappe.msgprint(__('Please select at least one asset.'));
                return;
            }

            const asset_names = selected.map(row => row.name);

            frappe.call({
                method: 'frappe.desk.page.server_script.server_script.run',
                args: {
                    script_name: 'Multiple Asset Tag',
                    asset_names: JSON.stringify(asset_names)
                },
                callback: function(r) {
                    const data = r.message;

                    let html = '';
                    data.forEach(asset => {
                        html += `
                            <div style="border:1px solid #000; padding:10px; margin:5px; width:45%; display:inline-block;">
                                <b>${asset.name}</b><br>
                                ${asset.item_name}<br>
                                Brand: ${asset.custom_brand_name}<br>
                                Model: ${asset.custom_model}<br>
                                Serial: ${asset.custom_serial_no}<br>
                                Cost: ₱${asset.gross_purchase_amount}
                            </div>
                        `;
                    });

                    const win = window.open('', '_blank');
                    win.document.write(`<html><head><title>Asset Tags</title></head><body>${html}</body></html>`);
                    win.document.close();
                    win.print();
                }
            });
        });
    }
};

frappe.ui.form.on("Payment Entry", {
    refresh(frm) {
        // Add custom button for Supplier only and if doc is in Draft
        if (frm.doc.docstatus === 0 && frm.doc.party_type === "Supplier") {
            frm.add_custom_button("Load Tax Template", async function () {
                await set_tax_template_only(frm);
            });
        }
    }
});

async function set_tax_template_only(frm) {
    // Validate required fields
    if (!frm.doc.company || !frm.doc.party || !frm.doc.paid_amount) {
        frappe.msgprint("Please make sure <b>Company</b>, <b>Supplier</b>, and <b>Paid Amount</b> are all filled.");
        return;
    }

    try {
        // Fetch Supplier
        const supplier = await frappe.db.get_doc("Supplier", frm.doc.party);

        if (!supplier.tax_category) {
            frappe.msgprint(`Supplier <b>${frm.doc.party}</b> has no <b>Tax Category</b> defined.`);
            return;
        }

        // Log what values we are using to query
        console.log(`[TAX TEMPLATE LOOKUP] Company: ${frm.doc.company}, Tax Category: ${supplier.tax_category}`);

        // Query the appropriate Purchase Tax Template
        const result = await frappe.db.get_value("Purchase Taxes and Charges Template", {
            company: frm.doc.company,
            tax_category: supplier.tax_category
        }, "name");

        if (result && result.name) {
            // Set the field — this will trigger ERPNext’s logic to populate deductions
            await frm.set_value("purchase_taxes_and_charges_template", result.name);
            await frm.refresh_field("purchase_taxes_and_charges_template");
            frappe.msgprint(`Applied tax template: <b>${result.name}</b>`);
        } else {
            frappe.msgprint(`No Purchase Tax Template found for:<br>Company: <b>${frm.doc.company}</b><br>Tax Category: <b>${supplier.tax_category}</b>`);
        }

    } catch (err) {
        console.error("Error during tax template set:", err);
        frappe.msgprint("Something went wrong. Check browser console.");
    }
}

