});

frappe.ui.form.on('Stock Entry Reference Detail', {
    fetch_items: function (frm, cdt, cdn) {
        const row = locals[cdt][cdn];

        if (!row.reference_type || !row.reference_name) {
            frappe.msgprint("Please select Reference Type and Reference Name in the parent form.");
            return;
        }
        if (!frm.doc.source_warehouse || !frm.doc.target_warehouse) {
            frappe.msgprint("Please select default Source and Target Warehouse.");
            return;
        }

        // escapeHTML utility
        function escapeHTML(text) {
            if (text === null || text === undefined) return "";
            return String(text)
                .replace(/&/g, "&amp;")
                .replace(/</g, "&lt;")
                .replace(/>/g, "&gt;")
                .replace(/"/g, "&quot;")
                .replace(/'/g, "&#039;")
                .replace(/\\/g, "&#092;");
        }

        frappe.db.get_value(row.reference_type, row.reference_name, 'company')
            .then(r => {
                if (r && r.message) {
                    let mycomp = r.message.company;

                    frappe.call({
                        method: "StockEntryReferenceFetchItems", // Adjust to your Python path
                        args: {
                            reference_type: row.reference_type,
                            reference_name: row.reference_name,
                            company: mycomp
                        },
                        callback: function (r) {
                            if (!r.data || r.data.length === 0) {
                                frappe.msgprint("No items found.");
                                return;
                            }

                            const items = r.data;

                            const table_html = `
                                <table class="table table-bordered">
                                    <thead>
                                        <tr>
                                            <th><input type="checkbox" id="select_all_items" /></th>
                                            <th>Item Code</th>
                                            <th>Item Name</th>
                                            <th>Qty</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        ${items.map((item, idx) => `
                                            <tr>
                                                <td><input type="checkbox" class="select-item" data-idx="${idx}" /></td>
                                                <td><a href="/app/item/${escapeHTML(item.item_code)}" target="_blank">${escapeHTML(item.item_code)}</a></td>
                                                <td>${escapeHTML(item.item_name)}</td>
                                                <td>${escapeHTML(item.qty)}</td>
                                            </tr>
                                        `).join('')}
                                    </tbody>
                                </table>
                            `;

                            const dialog = new frappe.ui.Dialog({
                                title: 'Select Items to Add',
                                fields: [
                                    {
                                        fieldtype: 'HTML',
                                        fieldname: 'items_html',
                                        options: table_html
                                    }
                                ],
                                primary_action_label: 'Add Selected Items',
                                primary_action() {
                                    const selected_items = [];
                                    const checkboxes = dialog.$wrapper.find('.select-item:checked');

                                    checkboxes.each(function () {
                                        const idx = parseInt($(this).data('idx'));
                                        if (!isNaN(idx)) {
                                            selected_items.push(items[idx]);
                                        }
                                    });

                                    selected_items.forEach(item => {
                                        const child = frm.add_child("transfer_items");
                                        child.item_code = item.item_code;
                                        child.item_name = item.item_name;
                                        child.issued_qty = item.qty;
                                        child.uom = item.stock_uom;
                                        child.reference_doc = row.reference_name || '';
                                    });

                                    frm.refresh_field("transfer_items");
                                    dialog.hide();
                                }
                            });

                            dialog.show();

                            setTimeout(() => {
                                dialog.$wrapper.find('#select_all_items').on('change', function () {
                                    const checked = $(this).is(':checked');
                                    dialog.$wrapper.find('.select-item').prop('checked', checked);
                                });
                            }, 300);
                        }
                    });
                }
            });
    }
});

frappe.ui.form.on("Warehouse Transfer", {
    refresh(frm) {
        // 🔒 Case 1: Final workflow status = "Received"
        if (frm.doc.transfer_status === "Received") {
            frm.set_read_only();
            frappe.show_alert({
                message: __("This document is already Received and cannot be modified."),
                indicator: "red"
            });
        }

        // 🔒 Case 2: Status = "Transferred" and user has access only to source warehouse
        else if (frm.doc.transfer_status === "Transferred") {
            frappe.call({
                method: "qcmc_logic.utils.check_warehouse_access",
                args: {
                    user: frappe.session.user,
                    warehouse: frm.doc.target_warehouse
                },
                callback: function (r) {
                    if (r.message === false) {
                        frm.set_read_only();
                        frappe.show_alert({
                            message: __("You cannot modify this document as it is already Transferred."),
                            indicator: "orange"
                        });
                    }
                }
            });
        }

        // 🔗 Source Company Docs
        const user_company = frappe.defaults.get_user_default("company");

        // Dates → use posting_date of transfer, fallback to today
        const from_date = frm.doc.posting_date || frappe.datetime.get_today();
        const to_date = from_date;

        // If logged in as Source Company → show Source ledgers
        if (user_company === frm.doc.source_company) {
            frm.add_custom_button(__('Stock Ledger'), function() {
                frappe.set_route('query-report', 'Stock Ledger', {
                    company: frm.doc.source_company,
                    from_date: from_date,
                    to_date: to_date,
                    voucher_type: "Warehouse Transfer",
                    voucher_no: frm.doc.name
                });
            }, __('View'));
        
            
            frm.add_custom_button(__('Accounting Ledger'), function() {
                frappe.set_route('query-report', 'General Ledger', {
                    company: frm.doc.source_company,
                    from_date: from_date,
                    to_date: to_date,
                    voucher_no: frm.doc.source_journal_entry,
                    include_dimensions: 1,
                    include_default_book_entries: 1
                });
            }, __('View'));
            
        }
        
        // If logged in as Target Company → show Target SLEs
        if (user_company === frm.doc.target_company) {
            frm.add_custom_button(__('Stock Ledger'), function() {
                frappe.set_route('query-report', 'Stock Ledger', {
                    company: frm.doc.target_company,
                    from_date: from_date,
                    to_date: to_date,
                    voucher_type: "Warehouse Transfer",
                    voucher_no: frm.doc.name
                });
            }, __('View'));
        
            
            frm.add_custom_button(__('Accounting Ledger'), function() {
                frappe.set_route('query-report', 'General Ledger', {
                    company: frm.doc.target_company,
                    from_date: from_date,
                    to_date: to_date,
                    voucher_no: frm.doc.target_journal_entry,
                    include_dimensions: 1,
                    include_default_book_entries: 1
                });
            }, __('View'));
            
        }
    }
});


function open_update_dialog(frm) {
    const existing_items = frm.doc.transfer_items || [];
    let rows_html = '';

    existing_items.forEach((row, idx) => {
        rows_html += generate_row_html(row, idx, false);
    });

    const dialog = new frappe.ui.Dialog({
        title: 'Update Received Items',
        size: 'extra-large',
        fields: [
            {
                fieldname: 'items_table',
                label: 'Items',
                fieldtype: 'HTML'
            },
            {
                fieldname: 'add_row',
                fieldtype: 'Button',
                label: 'Add Row',
                click() {
                    const idx = $('.item-row').length;
                    const new_row_html = generate_row_html({}, idx, true);
                    $('#custom-items-table tbody').append(new_row_html);
                    init_link_fields(idx);
                }
            },
            {
                fieldname: 'delete_selected',
                fieldtype: 'Button',
                label: 'Delete Selected Rows',
                click() {
                    $('#custom-items-table tbody tr').each(function () {
                        const $tr = $(this);
                        const is_new = $tr.attr('data-new') === '1';
                        const is_checked = $tr.find('.row-checkbox').is(':checked');

                        if (is_new && is_checked) {
                            $tr.remove();
                        }
                    });
                }
            }
        ],
        primary_action_label: 'Save to Form',
        primary_action() {
            $('#custom-items-table tbody tr').each(function () {
                const $tr = $(this);
                const idx = cint($tr.attr('data-idx'));
                const is_new = $tr.attr('data-new') === '1';
        
                if (is_new) {
                    // Create a new row in child table
                    let child = frm.add_child('transfer_items');
                    child.item_code = $(`#item_code_input_${idx}`).val();
                    child.item_name = $tr.find('.item_name').text();
                    child.uom = $(`#uom_input_${idx}`).val();
                    child.issued_qty = flt($tr.find('.issued_qty').text());  // will be 0
                    child.received_qty = flt($tr.find('.received_qty').val());
                    child.reference_doc = $tr.find('.reference_doc').text();
                } else {
                    // Update existing row
                    const row = frm.doc.transfer_items[idx];
                    if (row) {
                        row.received_qty = flt($tr.find('.received_qty').val());
                    }
                }
            });
        
            frm.refresh_field('transfer_items');
            dialog.hide();
        }
    });

    const html = `
        <table class="table table-bordered" id="custom-items-table">
            <thead>
                <tr>
                    <th style="width:30px;"></th>
                    <th>Item Code</th>
                    <th>Item Name</th>
                    <th>UOM</th>
                    <th>Issued Qty</th>
                    <th>Received Qty</th>
                    <th>Variance</th>
                    <th>Reference Doc</th>
                </tr>
            </thead>
            <tbody>${rows_html}</tbody>
        </table>
    `;
    dialog.fields_dict.items_table.$wrapper.html(html);

    $('.item-row[data-new="1"]').each(function () {
        const idx = $(this).attr('data-idx');
        init_link_fields(idx);
    });

    dialog.$wrapper.on('input', '.received_qty', function () {
        const $tr = $(this).closest('tr');
        const issued = flt($tr.find('.issued_qty').text());
        const received = flt($(this).val());
        $tr.find('.variance').text((issued - received).toFixed(2));
    });

    dialog.show();
}

function generate_row_html(row, idx, is_new) {
    return `
        <tr class="item-row" data-idx="${idx}" data-new="${is_new ? 1 : 0}">
            <td>${is_new ? `<input type="checkbox" class="row-checkbox">` : ''}</td>
            <td>${is_new
                ? `<div id="item_code_${idx}" class="link-field-placeholder"></div>`
                : `<input type="text" class="form-control item_code" value="${frappe.utils.escape_html(row.item_code || '')}" readonly>`}</td>
            <td><span class="item_name text-ellipsis" title="${frappe.utils.escape_html(row.item_name || '')}" style="max-width:200px; display:inline-block; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${frappe.utils.escape_html(row.item_name || '')}</span></td>
            <td>${is_new
                ? `<div id="uom_${idx}" class="link-field-placeholder"></div>`
                : `<input type="text" class="form-control uom" value="${frappe.utils.escape_html(row.uom || '')}" readonly>`}</td>
            <td><span class="issued_qty">${flt(row.issued_qty || 0).toFixed(2)}</span></td>
            <td><input type="number" class="form-control received_qty" value="${flt(row.received_qty || 0)}"></td>
            <td><span class="variance">${flt((row.issued_qty || 0) - (row.received_qty || 0)).toFixed(2)}</span></td>
            <td><span class="reference_doc text-ellipsis" title="${frappe.utils.escape_html(row.reference_doc || '')}" style="max-width:200px; display:inline-block; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${frappe.utils.escape_html(row.reference_doc || '')}</span></td>
        </tr>
    `;
}

function init_link_fields(idx) {
    const item_code_field = frappe.ui.form.make_control({
        df: {
            fieldtype: 'Link',
            options: 'Item',
            fieldname: `item_code_input_${idx}`,
            placeholder: 'Item Code',
            change() {
                const item_code = item_code_field.get_value();
                if (item_code) {
                    frappe.db.get_doc('Item', item_code).then(doc => {
                        $(`.item-row[data-idx="${idx}"] .item_name`).text(doc.item_name);
                        $(`.item-row[data-idx="${idx}"] .reference_doc`).text('');
                        $(`.item-row[data-idx="${idx}"] .issued_qty`).text('0.00');
                        $(`.item-row[data-idx="${idx}"] .received_qty`).val('0');
                        $(`.item-row[data-idx="${idx}"] .variance`).text('0.00');

                        const uom_placeholder = $(`#uom_${idx}`);
                        uom_placeholder.empty();

                        frappe.ui.form.make_control({
                            df: {
                                fieldtype: 'Link',
                                options: 'UOM',
                                fieldname: `uom_input_${idx}`,
                                placeholder: 'UOM',
                                default: doc.stock_uom
                            },
                            parent: uom_placeholder,
                            render_input: true
                        }).set_value(doc.stock_uom);
                    });
                }
            }
        },
        parent: $(`#item_code_${idx}`),
        render_input: true
    });
}

