        if (["Draft", "For Corp IE Approval", "For Approval", "For BCC Approval", "For VP Sales Approval", "For VP Procurement"].includes(state)) {
            new_status = "Pending";
        } 
        else if (["Approved", "Acknowledged"].includes(state)) {
            new_status = "Open & Approved";
        } 
        else if (state === "Cancelled") {
