function set_dynamic_workflow_actions(frm) {
    const dept = frm.doc.department || "";
    const state = frm.doc.workflow_state || "";

    const plant_depts = ["Plant - QC", "Plant - MC"];
    const finance_depts = ["Finance - QC", "Finance - MC"];
    const sales_depts = ["Sales - QC", "Sales - MC"];
    const proc_depts = ["Procurement - QC", "Procurement - MC"];

    // Reset the custom action tracker each time
    frm.custom_action_added = new Set();

    // DRAFT state
    if (state === "Draft") {
        if (plant_depts.includes(dept)) {
            add_custom_action(frm, "Submit to Corp IE");
        } else {
            add_custom_action(frm, "Submit for Approval");
        }
    }

    // FOR APPROVAL state
    else if (state === "For Approval") {
        if (finance_depts.includes(dept)) {
            add_custom_action(frm, "For BCC Approval");
        } else if (sales_depts.includes(dept)) {
            add_custom_action(frm, "For VP Sales Approval");
        } else if (proc_depts.includes(dept)) {
            add_custom_action(frm, "For VP Procurement");
        } else {
            add_custom_action(frm, "Approve");
        }
    }

    // FOR CORP IE APPROVAL state
    else if (state === "For Corp IE Approval") {
        add_custom_action(frm, "Approve");
    }

    // FOR BCC APPROVAL state
    else if (state === "For BCC Approval") {
        add_custom_action(frm, "Approve");
    }
    
    // FOR VP Sales Approval state
    else if (state === "For VP Sales Approval") {
        add_custom_action(frm, "Approve");
    }

    // For VP Procurement Approval state
    else if (state === "For VP Procurement Approval") {
        add_custom_action(frm, "Approve");
    }


    // APPROVED state
    else if (state === "Approved") {
        add_custom_action(frm, "Acknowledge");
    }

    // ACKNOWLEDGED state
    else if (state === "Acknowledged") {
        add_custom_action(frm, "Cancel");
    }

    // Keep default system buttons visible
}

function add_custom_action(frm, action_name) {
    // Avoid duplicates
    if (frm.custom_action_added.has(action_name)) return;

    frm.page.add_action_item(action_name, function() {
        frappe.xcall("frappe.model.workflow.apply_workflow", {
            doc: frm.doc,
            action: action_name
        }).then(() => frm.reload_doc());
    });

    frm.custom_action_added.add(action_name);
}

