// ---------------------------------------------------------
// Update Payment Entry Paid Amount based on child rows
// ---------------------------------------------------------
function update_paid_amount(frm) {
    let total_paid = 0;

    (frm.doc.custom_expense_details || []).forEach(row => {
        total_paid += flt(row.base_amt || 0);
    });

    frm.set_value("paid_amount", total_paid);
    frm.refresh_field("paid_amount");
}

// ---------------------------------------------------------
// Compute misc_amt per child row
// ---------------------------------------------------------
function compute_misc_in_child(frm, cdt, cdn) {
    let row = frappe.get_doc(cdt, cdn);

    let base = flt(row.base_amt);
    let taxable = flt(row.taxable_amount);

    // ⭐ Modify formula if you need a different one
    let misc = base - taxable;

    frappe.model.set_value(cdt, cdn, "misc_amt", misc);

    frm.refresh_field("custom_expense_details");
}

// ---------------------------------------------------------
// Compute tax per child row (supports VAT inclusive + EWT)
// ---------------------------------------------------------
async function compute_taxes_in_child(frm, cdt, cdn) {
    const row = frappe.get_doc(cdt, cdn);
    // Use base_amt as the Gross (VAT Inclusive) amount for this line
    const net_amount = flt(row.taxable_amount); 

    if (!row.tax_template || !net_amount) {
        // Clear EWT if no template or amount, and call update_paid_amount
        frappe.model.set_value(cdt, cdn, "input_tax", 0);
        frappe.model.set_value(cdt, cdn, "ewt_payable", 0);
        update_paid_amount(frm); // Update total paid (since EWT changed)
        return;
    }

    try {
        const template = await frappe.db.get_doc(
            "Purchase Taxes and Charges Template",
            row.tax_template
        );

        let vat_exclusive_base = net_amount;
        let total_vat = 0;
        let total_ewt = 0;
        let rate_used = 0;
        let input_tax = 0;
        let account_tax = "";

        // --- PHASE 1: Determine VAT and Net-of-VAT Base (DEBIT: Expense + Input Tax) ---
        template.taxes.forEach(tax => {
            const rate = flt(tax.rate) / 100;
            const acc = (tax.account_head || "").toLowerCase();

            // Only calculate VAT if it's marked as INCLUSIVE and is Input Tax
            if (tax.included_in_paid_amount && acc.includes("input tax")) {
                const vat_amount = (net_amount / (1 + rate)) * rate;
                input_vat = vat_amount;
                total_vat += vat_amount;
                // Determine the true expense base (Net of VAT)
                vat_exclusive_base = net_amount - vat_amount;
            }
        });

        // --- PHASE 2: Calculate EWT based on VAT-Exclusive Base (CREDIT: EWT Payable) ---
        template.taxes.forEach(tax => {
            const rate = flt(tax.rate) / 100;
            const acc = (tax.account_head || "").toLowerCase();

            // EWT is generally calculated on the VAT-EXCLUSIVE amount
            if (acc.includes("ewt")) {
                account_tax = acc;
                rate_used = rate;
                const ewt_amount = vat_exclusive_base * rate;
                total_ewt += ewt_amount;
            }
        });
         // ----------------------------------------------------
        // 🔍 DEBUG LOGS (Your request — no logic changed)
        // ----------------------------------------------------
        console.log("==============================================");
        console.log(" Computation Debug for Row:", row.name);
        console.log("----------------------------------------------");
        console.log("Taxable Amount (Input):        ", net_amount);
        console.log("VAT Exclusive Base:            ", vat_exclusive_base);
        console.log("VAT Amount:                    ", input_tax);
        console.log("Account:                       ", account_tax);
        console.log("Rate used for ewt:             ", rate_used);
        console.log("Total Input Tax Computed:      ", total_vat);
        console.log("Total EWT Payable Computed:    ", total_ewt);
        console.log("Tax Template:                  ", row.tax_template);
        console.log("==============================================");
        // ----------------------------------------------------


        // -----------------------------------------
        // Update the fields on the child table
        // -----------------------------------------
        frappe.model.set_value(cdt, cdn, "input_tax", total_vat);
        frappe.model.set_value(cdt, cdn, "ewt_payable", total_ewt);
        // Note: The base_amt field is unchanged here; it remains the Gross Input amount.

        frm.refresh_fields("custom_expense_details");
        // Update the total paid amount on the parent document
        update_paid_amount(frm); 

    } catch (err) {
        console.error(err);
        frappe.msgprint("Error loading Purchase Tax Template.");
    }
}

frappe.ui.form.on("Staffing Plan", {
    refresh: function(frm) {
        // Only run if there are child rows
        if(frm.doc.staffing_details && frm.doc.staffing_details.length > 0) {
            frm.doc.staffing_details.forEach(function(d, idx) {
                frappe.call({
                    method: "qcmc_logic.overrides.StaffingPlanOverrides.get_current_count",
                    args: {
                        docname: frm.doc.name,     // may be "new-xxxx" for unsaved docs
                        child_idx: idx,
                        data: frm.doc              // send entire doc JSON so Python can read it
                    },
                    callback: function(r) {
                        if (r.message !== undefined) {
                            frappe.model.set_value(d.doctype, d.name, "current_count", r.message);
                            frappe.show_alert(`Current count: ${r.message}`);
                        }
                    }
                });
            });
        }
    }
});

frappe.ui.form.on("Job Requisition", {

    custom_additional_manpower(frm) {
        // If additional manpower is TRUE (1), zero out custom_vacancies
        if (frm.doc.custom_additional_manpower) {
            frm.set_value("custom_vacancies", 0);
        } else {
            // If switched back to false, recalculate vacancies based on staffing plan + designation
            frappe.run_serially([
                () => frm.trigger("designation")
            ]);
        }
    },

    designation(frm) {
        // Do nothing if staffing plan or designation is missing
        if (!frm.doc.custom_staffing_plan || !frm.doc.designation) return;

        // If additional manpower = TRUE, skip fetching and force vacancies = 0
        if (frm.doc.custom_additional_manpower) {
            frm.set_value("custom_vacancies", 0);
            return;
        }

        // Fetch staffing plan details
        frappe.call({
            method: "frappe.client.get",
            args: {
                doctype: "Staffing Plan",
                name: frm.doc.custom_staffing_plan
            },
            callback: function (r) {
                if (!r.message) return;

                const sp = r.message;
                let matching_row = null;

                // Find row matching selected designation
                if (sp.staffing_details?.length) {
                    matching_row = sp.staffing_details.find(
                        row => row.designation === frm.doc.designation
                    );
                }

                if (matching_row) {
                    frm.set_value("custom_vacancies", matching_row.vacancies || 0);
                } else {
                    frm.set_value("custom_vacancies", 0);
                }
            }
        });
    },

    custom_staffing_plan(frm) {
        // When SP changes, recalc if designation already selected
        if (frm.doc.custom_staffing_plan && frm.doc.designation) {
            frm.trigger("designation");
        }
    }
});
